# Synthetic direnv export bash output fixture
# Mimics what `direnv export bash` would emit for a simple .envrc

export DIRENV_DIR=/home/user/myproject
export DIRENV_FILE=/home/user/myproject/.envrc
export DIRENV_DIFF=eJy...base64...
export MYPROJECT_VAR=set_by_direnv
export PATH=/home/user/myproject/bin:/usr/local/bin:/usr/bin:/bin
